-inline mutable_buffer operator+(const mutable_buffer& mb, size_t n) noexcept
-{
-  return mutable_buffer(static_cast<char*>(mb.data()) + (std::min)(n, mb.size()),
-                        mb.size() - (std::min)(n, mb.size()));
-}
