-    return _data;
-  }
-  constexpr size_t size() const noexcept
-  {
-    return _size;
-  }
-  const_buffer& operator+=(size_t n) noexcept
-  {
-    const auto shift = (std::min)(n, _size);
-    _data = static_cast<const char*>(_data) + shift;
