+void updateTree(TreeNode* tree, GLfloat x_pos, GLfloat y_pos, GLfloat x_offset, GLfloat y_offset )
+{
+    ControlNode* d = dynamic_cast<ControlNode*> (tree);
+    if (d == NULL)
