+
+                    // 3.4) the "for" loop must end here.
+                    break;
+                } else if (ChildStates[i] == Success) //If the child i returns success, the sequence star node can tick the next child
+                {
+                    i++;
+                }
+
+
+
+            }
+
+            if (i == M)
